export function parseHireFromListingHumanlessInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedHireFromListingHumanlessInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 11) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 11,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === AGENC_COORDINATION_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      task: getNextAccount(),
      escrow: getNextAccount(),
      hireRecord: getNextAccount(),
      taskValidationConfig: getNextAccount(),
      listing: getNextAccount(),
      protocolConfig: getNextAccount(),
      moderationConfig: getNextAccount(),
      listingModeration: getNextOptionalAccount(),
      authorityRateLimit: getNextAccount(),
      creator: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getHireFromListingHumanlessInstructionDataDecoder().decode(
      instruction.data,
    ),
  };
}
